def is_palindrome(string: str) -> bool:
    # Logic: Check if the given string reads the same forwards and backwards.
    return string == string[::-1]

def make_palindrome(string: str) -> str:
    # Logic: Find the shortest palindrome that begins with a supplied string.
    # 1. Identify the longest postfix of the string that is a palindrome.
    for i in range(len(string), -1, -1):
        if string[:i] == string[:i][::-1]:
            break
    # 2. Append to the end of the string reverse of a string prefix that comes before the palindromic suffix.
    return string + string[:i][::-1]
